func (this *ArkhamCore) ParseTrade(trade any, optionalArgs ...any) any {
	//
	// fetchTrades
	//
	//        {
	//            "symbol": "BTC_USDT_PERP",
	//            "revisionId": "1130514101",
	//            "size": "0.01668",
	//            "price": "116309.57",
	//            "takerSide": "sell",
	//            "time": "1753439710374047"
	//        }
	//
	// fetchMyTrades
	//
	//        {
	//            "symbol": "SOL_USDT",
	//            "revisionId": "891839406",
	//            "size": "0.042",
	//            "price": "185.06",
	//            "takerSide": "sell",
	//            "time": "1753773952039342",
	//            "orderId": "3717304929194",
	//            "userSide": "sell",
	//            "quoteFee": "0.00777252",
	//            "arkmFee": "0",
	//            "clientOrderId": ""
	//        }
	//
	market := GetArg(optionalArgs, 0, nil)
	_ = market
	var marketId any = this.SafeString(trade, "symbol")
	market = this.SafeMarket(marketId, market)
	var timestamp any = this.SafeIntegerProduct(trade, "time", 0.001)
	var quoteFee any = this.SafeNumber(trade, "quoteFee")
	var arkmFee any = this.SafeNumber(trade, "arkmFee")
	var fee any = nil
	if IsTrue(!IsEqual(quoteFee, nil)) {
		fee = map[string]any{
			"cost":     quoteFee,
			"currency": GetValue(market, "quote"),
		}
	} else if IsTrue(!IsEqual(arkmFee, nil)) {
		fee = map[string]any{
			"cost":     arkmFee,
			"currency": "ARKM",
		}
	}
	return this.SafeTrade(map[string]any{
		"info":         trade,
		"id":           this.SafeString(trade, "revisionId"),
		"timestamp":    timestamp,
		"datetime":     this.Iso8601(timestamp),
		"symbol":       GetValue(market, "symbol"),
		"type":         nil,
		"side":         this.SafeString2(trade, "userSide", "takerSide"),
		"takerOrMaker": nil,
		"price":        this.SafeString(trade, "price"),
		"amount":       this.SafeString(trade, "size"),
		"cost":         nil,
		"fee":          fee,
		"order":        this.SafeString(trade, "orderId"),
	}, market)
}

