func (this *ArkhamCore) ParseTransaction(transaction any, optionalArgs ...any) any {
	//
	//        {
	//            "id": "238644",
	//            "symbol": "SOL",
	//            "amount": "0.104",
	//            "time": "1753436404000000",
	//            "confirmed": true,
	//            "transactionHash": "1DRxbbyePTsMuB82SDf2fG5gLXH5iYnY8TQDstDPLULpLtjMJtF1ug1T4Mf8B6DSb8fp2sb5YtdbyqieZ2tkE1Ve",
	//            "chain": "Solana",
	//            "depositAddress": "12NauJ26TUT9aYkpId7YdePJJDRMGbAsEMVoTVUvBErV",
	//            "price": "180.322010164"
	//        }
	//
	currency := GetArg(optionalArgs, 0, nil)
	_ = currency
	var address any = this.SafeString(transaction, "depositAddress")
	var timestamp any = this.SafeIntegerProduct(transaction, "time", 0.001)
	var confirmd any = this.SafeBool(transaction, "confirmed")
	var status any = nil
	if IsTrue(confirmd) {
		status = "ok"
	}
	var currencyId any = this.SafeString(transaction, "symbol")
	var code any = this.SafeCurrencyCode(currencyId, currency)
	return map[string]any{
		"info":        transaction,
		"id":          this.SafeString(transaction, "id"),
		"txid":        this.SafeString(transaction, "transactionHash"),
		"type":        nil,
		"currency":    code,
		"network":     this.NetworkIdToCode(this.SafeString(transaction, "chain")),
		"amount":      this.SafeNumber(transaction, "amount"),
		"status":      status,
		"timestamp":   timestamp,
		"datetime":    this.Iso8601(timestamp),
		"address":     address,
		"addressFrom": nil,
		"addressTo":   address,
		"tag":         nil,
		"tagFrom":     nil,
		"tagTo":       nil,
		"updated":     nil,
		"comment":     nil,
		"fee":         nil,
		"internal":    false,
	}
}

/**
 * @method
 * @name arkham#fetchTradingFees
 * @description fetch the trading fees for multiple markets
 * @see https://arkm.com/docs#get/account/fees
 * @param {object} [params] extra parameters specific to the exchange API endpoint
 * @param {string} [params.subType] "linear" or "inverse"
 * @returns {object} a dictionary of [fee structures]{@link https://docs.ccxt.com/?id=fee-structure} indexed by market symbols
 */
func (this *ArkhamCore) FetchTradingFees(optionalArgs ...any) <-chan any {
	ch := make(chan any)
	go func() any {
		defer close(ch)
		defer ReturnPanicError(ch)
		params := GetArg(optionalArgs, 0, map[string]any{})
		_ = params

		retRes19838 := (<-this.LoadMarkets())
		PanicOnError(retRes19838)

		response := (<-this.V1PrivateGetAccountFees(params))
		PanicOnError(response)
		//
		// {
		//   "perpMakerFee": "1.23",
		//   "perpTakerFee": "1.23",
		//   "spotMakerFee": "1.23",
		//   "spotTakerFee": "1.23"
		// }
		//
		var symbols any = ObjectKeys(this.Markets)
		var result any = map[string]any{}
		var spotMaker any = this.SafeNumber(response, "spotMakerFee")
		var spotTaker any = this.SafeNumber(response, "spotTakerFee")
		var perpMaker any = this.SafeNumber(response, "perpMakerFee")
		var perpTaker any = this.SafeNumber(response, "perpTakerFee")
		for i := 0; IsLessThan(i, GetArrayLength(symbols)); i++ {
			var symbol any = GetValue(symbols, i)
			var market any = GetValue(this.Markets, symbol)
			AddElementToObject(result, symbol, map[string]any{
				"info":   response,
				"symbol": symbol,
			})
			if IsTrue(GetValue(market, "spot")) {
				AddElementToObject(GetValue(result, symbol), "maker", spotMaker)
				AddElementToObject(GetValue(result, symbol), "taker", spotTaker)
			} else if IsTrue(IsTrue(GetValue(market, "swap")) || IsTrue(GetValue(market, "future"))) {
				AddElementToObject(GetValue(result, symbol), "maker", perpMaker)
				AddElementToObject(GetValue(result, symbol), "taker", perpTaker)
			}
		}

		ch <- result
		return nil

	}()
	return ch
}

